function.arguments:
{"command": "cat > test_comprehensive.sql << 'EOF'
-- Test all variations
SELECT IFNULL(a, b) FROM t1;
SELECT ifnull(a, b) FROM t1;
SELECT IfNull(a, b) FROM t1;
SELECT NVL(a, b) FROM t1;
SELECT nvl(a, b) FROM t1;
SELECT Nvl(a, b) FROM t1;

-- Should not trigger
SELECT COALESCE(a, b) FROM t1;
SELECT coalesce(a, b) FROM t1;
SELECT Coalesce(a, b) FROM t1;
SELECT ISNULL(a, b) FROM t1;  -- Different function
SELECT NULLIF(a, b) FROM t1;  -- Different function

-- Complex cases
SELECT 
    IFNULL(x, y) as col1,
    NVL(p, q) as col2,
    COALESCE(m, n) as col3
FROM table1
WHERE IFNULL(status, 'active') = 'active'
  AND NVL(score, 0) > 10;
EOF"}

